# WRONG: new client (and new pool) on every request
@app.post("/agent/run")
async def run_agent(body: dict):
    async with httpx.AsyncClient() as client:    # ← anti-pattern
        resp = await client.post(URL, json=body)
        return resp.json()

# RIGHT: reuse the application-scoped client
@app.post("/agent/run")
async def run_agent(request: Request, body: dict):
    client: httpx.AsyncClient = request.app.state.http   # ← one shared client
    resp = await client.post(URL, json=body)
    return resp.json()

# WRONG: synchronous call blocks the event loop
@app.post("/agent/tool")
async def call_tool(body: dict):
    resp = requests.get("https://api.example.com/tool", params=body)  # blocks!
    return resp.json()

# RIGHT: async client yields control back to the event loop
@app.post("/agent/tool")
async def call_tool(request: Request, body: dict):
    client: httpx.AsyncClient = request.app.state.http
    resp = await client.get("https://api.example.com/tool", params=body)
    return resp.json()

# ALSO RIGHT if you cannot avoid a sync library:
# run it in a thread pool so the event loop remains free
import asyncio
@app.post("/agent/tool")
async def call_tool_sync_lib(body: dict):
    resp = await asyncio.to_thread(requests.get, "https://api.example.com/tool", params=body)
    return resp.json()

import httpx
import pytest
import respx

@respx.mock
@pytest.mark.asyncio
async def test_fetch_tool():
    respx.get("https://api.example.com/tool").mock(
        return_value=httpx.Response(200, json={"result": 42})
    )
    async with httpx.AsyncClient() as client:
        resp = await client.get("https://api.example.com/tool")
        assert resp.json() == {"result": 42}
